model = load_model()
elo_ratings = load_elo_ratings()


st.markdown("""
<div style='padding: 40px 0 8px 0;'>
    <div class='hero-badge'>FIFA World Cup 2026</div>
    <div class='hero-title'>Match Score Predictor</div>
    <div class='hero-sub'>Poisson regression + Elo ratings · Monte Carlo simulation · Real 2026 draw</div>
</div>
""", unsafe_allow_html=True)

st.markdown("<div class='section-label'>Head-to-head predictor</div>", unsafe_allow_html=True)

team_list = sorted(elo_ratings.keys())
col1, spacer, col2 = st.columns([5, 1, 5])

with col1:
    home_team = st.selectbox(
        "Home team", team_list,
        index=team_list.index("Brazil") if "Brazil" in team_list else 0,
        label_visibility="collapsed"
    )
    url = flag_url(home_team)
    if url:
        st.markdown(f"<div style='margin-top:8px;'><img src='{url}' height='28' style='border-radius:3px;'> <span style='font-size:15px; font-weight:600; color:#fff; vertical-align:middle;'>{home_team}</span></div>", unsafe_allow_html=True)

with spacer:
    st.markdown("<div style='text-align:center; padding-top:8px; font-size:13px; color:rgba(255,255,255,0.25); font-weight:600;'>vs</div>", unsafe_allow_html=True)

with col2:
    away_team = st.selectbox(
        "Away team", team_list,
        index=team_list.index("Germany") if "Germany" in team_list else 1,
        label_visibility="collapsed"
    )
    url = flag_url(away_team)
    if url:
        st.markdown(f"<div style='margin-top:8px;'><img src='{url}' height='28' style='border-radius:3px;'> <span style='font-size:15px; font-weight:600; color:#fff; vertical-align:middle;'>{away_team}</span></div>", unsafe_allow_html=True)

st.markdown("<div style='margin-top:16px;'></div>", unsafe_allow_html=True)

if st.button("Predict match", type="primary", use_container_width=False):
    home_elo = elo_ratings.get(home_team, 1500)
    away_elo = elo_ratings.get(away_team, 1500)

    lambda_home, lambda_away = predict_expected_goals(
        model, home_elo, away_elo,
        tournament_weight=3.0
    )
    score_matrix = build_score_matrix(lambda_home, lambda_away)
    p_home_win, p_draw, p_away_win = win_draw_loss(score_matrix)

    st.markdown("<div style='margin-top:24px;'></div>", unsafe_allow_html=True)

    c1, c2, c3, c4 = st.columns(4)
    with c1:
        st.markdown(f"""
        <div style='background:rgba(255,255,255,0.03); border:1px solid rgba(255,255,255,0.08);
                    border-radius:12px; padding:16px 20px;'>
            <div style='font-size:11px; font-weight:600; letter-spacing:0.08em; text-transform:uppercase;
                        color:rgba(255,255,255,0.3); margin-bottom:6px;'>{home_team}</div>
            <div style='font-size:2rem; font-weight:700; color:#fff;'>{lambda_home:.2f}</div>
            <div style='font-size:11px; color:rgba(255,255,255,0.3); margin-top:2px;'>expected goals</div>
        </div>""", unsafe_allow_html=True)
    with c2:
        st.markdown(f"""
        <div style='background:rgba(255,255,255,0.03); border:1px solid rgba(255,255,255,0.08);
                    border-radius:12px; padding:16px 20px;'>
            <div style='font-size:11px; font-weight:600; letter-spacing:0.08em; text-transform:uppercase;
                        color:rgba(255,255,255,0.3); margin-bottom:6px;'>{away_team}</div>
            <div style='font-size:2rem; font-weight:700; color:#fff;'>{lambda_away:.2f}</div>
            <div style='font-size:11px; color:rgba(255,255,255,0.3); margin-top:2px;'>expected goals</div>
        </div>""", unsafe_allow_html=True)
    with c3:
        max_idx = np.unravel_index(score_matrix.argmax(), score_matrix.shape)
        st.markdown(f"""
        <div style='background:rgba(77,163,255,0.07); border:1px solid rgba(77,163,255,0.2);
                    border-radius:12px; padding:16px 20px;'>
            <div style='font-size:11px; font-weight:600; letter-spacing:0.08em; text-transform:uppercase;
                        color:rgba(77,163,255,0.6); margin-bottom:6px;'>Most likely score</div>
            <div style='font-size:2rem; font-weight:700; color:#4da3ff;'>{max_idx[0]} – {max_idx[1]}</div>
            <div style='font-size:11px; color:rgba(77,163,255,0.4); margin-top:2px;'>{score_matrix[max_idx]*100:.1f}% probability</div>
        </div>""", unsafe_allow_html=True)
    with c4:
        if p_home_win > p_away_win and p_home_win > p_draw:
            fav, fav_pct = home_team, p_home_win
        elif p_away_win > p_home_win and p_away_win > p_draw:
            fav, fav_pct = away_team, p_away_win
        else:
            fav, fav_pct = "Draw", p_draw
        st.markdown(f"""
        <div style='background:rgba(74,222,128,0.07); border:1px solid rgba(74,222,128,0.2);
                    border-radius:12px; padding:16px 20px;'>
            <div style='font-size:11px; font-weight:600; letter-spacing:0.08em; text-transform:uppercase;
                        color:rgba(74,222,128,0.6); margin-bottom:6px;'>Favourite</div>
            <div style='font-size:1.3rem; font-weight:700; color:#4ade80; line-height:1.2;'>{fav}</div>
            <div style='font-size:11px; color:rgba(74,222,128,0.4); margin-top:2px;'>{fav_pct*100:.1f}% to win</div>
        </div>""", unsafe_allow_html=True)

    st.markdown("<div style='margin-top:16px;'></div>", unsafe_allow_html=True)

    col_a, col_b, col_c = st.columns(3)
    prob_data = [
        (home_team, p_home_win, "#4da3ff"),
        ("Draw", p_draw, "rgba(255,255,255,0.4)"),
        (away_team, p_away_win, "#f97316"),
    ]
    for col, (label, prob, color) in zip([col_a, col_b, col_c], prob_data):
        bar_w = int(prob * 100)
        col.markdown(f"""
        <div style='background:rgba(255,255,255,0.03); border:1px solid rgba(255,255,255,0.07);
                    border-radius:10px; padding:14px 16px;'>
            <div style='font-size:12px; color:rgba(255,255,255,0.4); margin-bottom:6px;'>{label}</div>
            <div style='font-size:1.5rem; font-weight:700; color:{color}; margin-bottom:8px;'>{prob*100:.1f}%</div>
            <div style='height:4px; background:rgba(255,255,255,0.06); border-radius:4px;'>
                <div style='height:4px; width:{bar_w}%; background:{color}; border-radius:4px;'></div>
            </div>
        </div>""", unsafe_allow_html=True)

    st.markdown("<div style='margin-top:24px;'></div>", unsafe_allow_html=True)
    st.markdown("<div class='section-label'>Scoreline probability heatmap</div>", unsafe_allow_html=True)

    fig = go.Figure(data=go.Heatmap(
        z=score_matrix * 100,
        x=[str(a) for a in range(MAX_GOALS + 1)],
        y=[str(h) for h in range(MAX_GOALS + 1)],
        colorscale=[[0, 'rgba(255,255,255,0.03)'], [0.5, 'rgba(77,163,255,0.35)'], [1, '#1d8eff']],
        text=np.round(score_matrix * 100, 1),
        texttemplate="%{text}%",
        hovertemplate=f"{home_team}: %{{y}}<br>{away_team}: %{{x}}<br>Probability: %{{z:.1f}}%<extra></extra>",
        showscale=False,
    ))
    fig.update_layout(
        xaxis_title=f"{away_team} goals",
        yaxis_title=f"{home_team} goals",
        height=380,
        paper_bgcolor='rgba(0,0,0,0)',
        plot_bgcolor='rgba(255,255,255,0.02)',
        font=dict(color='rgba(255,255,255,0.5)', size=12),
        margin=dict(l=60, r=20, t=20, b=60),
        xaxis=dict(gridcolor='rgba(255,255,255,0.04)'),
        yaxis=dict(gridcolor='rgba(255,255,255,0.04)'),
    )
    st.plotly_chart(fig, use_container_width=True)

st.markdown("<div style='margin-top:48px;'></div>", unsafe_allow_html=True)
st.markdown("<div class='section-label'>Tournament simulator</div>", unsafe_allow_html=True)
st.markdown("""
<div style='font-size:13px; color:rgba(255,255,255,0.35); margin-bottom:20px; line-height:1.6;'>
    Simulates the real 2026 group draw end-to-end using Monte Carlo sampling.
    Each run is a different random outcome — not a forecast of what will happen.
</div>
""", unsafe_allow_html=True)

if "wc_sim" not in st.session_state:
    st.session_state.wc_sim = None

if st.button("Run full tournament simulation", type="primary"):
    with st.spinner("Simulating 48 teams, 72 group matches, full knockout stage..."):
        rng = np.random.default_rng()
        all_standings = simulate_all_groups(model, GROUPS, elo_ratings, rng)
        qualifiers, eliminated = rank_third_place_teams(all_standings)
        bracket = build_round_of_32(all_standings, qualifiers, rng)
        all_rounds, champion = simulate_full_knockout(model, bracket, elo_ratings, rng)

        st.session_state.wc_sim = {
            'all_standings': all_standings,
            'qualifiers': qualifiers,
            'eliminated': eliminated,
            'bracket': bracket,
            'all_rounds': all_rounds,
            'champion': champion,
        }

if st.session_state.wc_sim:
    sim = st.session_state.wc_sim

    champ_flag = flag_url(sim['champion'])
    flag_html = f"<img src='{champ_flag}' height='36' style='border-radius:4px; vertical-align:middle; margin-right:12px;'>" if champ_flag else ""
    st.markdown(f"""
    <div class='champion-banner'>
        <div class='label'>Simulated champion</div>
        <div class='name'>{flag_html}{sim['champion']}</div>
    </div>
    """, unsafe_allow_html=True)

    st.markdown("<div style='margin-top:24px;'></div>", unsafe_allow_html=True)

    tab1, tab2, tab3 = st.tabs(["Group stage", "Round of 32", "Knockout bracket"])

    with tab1:
        render_group_stage_tab(sim)
    with tab2:
        render_round_of_32_tab(sim)
    with tab3:
        render_knockout_tab(sim)
else:
    st.markdown("""
    <div style='background:rgba(255,255,255,0.02); border:1px dashed rgba(255,255,255,0.1);
                border-radius:12px; padding:32px; text-align:center;'>
        <div style='font-size:13px; color:rgba(255,255,255,0.3);'>
            Click the button above to simulate the entire World Cup
        </div>
    </div>
    """, unsafe_allow_html=True)